def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio > 1.5:
            priorities[i] = np.inf
            continue
        for outer in range(4):
            temp_ratio = ratio
            temp_score = 0
            for inner in range(5):
                if temp_ratio < 0.05:
                    temp_score += (0.05 - temp_ratio)**3
                elif temp_ratio < 0.3:
                    temp_score += (0.3 - temp_ratio) * 0.7
                elif temp_ratio < 0.7:
                    temp_score += np.log1p(temp_ratio) * 2
                else:
                    temp_score += np.sqrt(temp_ratio) * 1.5
                temp_ratio = temp_ratio ** (1/(inner+2))
                if temp_ratio < 0.01:
                    temp_score -= 0.1
                else:
                    temp_score += 0.05 * inner
            if (outer % 2) == 0:
                temp_score *= (1 + 0.1 * outer)
            else:
                temp_score /= (1 + 0.05 * outer)
            score += temp_score
            ratio = ratio ** 0.75
        if capacity < item * 0.7:
            score += (item - capacity) * 0.5
        if capacity > item * 1.5:
            score -= (capacity - item) * 0.2
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority + 10
    return priorities
